/* eslint-disable max-len */
// AUTO-GENERATED asset — Lumi mascot (red flame with books) for the onboarding
// email hero. Source: assets/lumi/Lumi_Books_Red.png, downscaled to 160x200.
// Inlined as base64 so it ships with the bundle (no runtime filesystem access)
// and renders without a public asset host.
import type {OnboardingEmailAttachment} from "./email_templates";

export const LUMI_MASCOT_CONTENT_ID = "lumi-mascot";

const LUMI_MASCOT_PNG_BASE64 =
  "";

/**
 * Inline image attachment for the mascot, referenced in the hero as
 * <img src="cid:lumi-mascot">. Add to the SendGrid attachments array.
 * @return {OnboardingEmailAttachment} the inline mascot attachment
 */
export function lumiMascotAttachment(): OnboardingEmailAttachment {
  return {
    content: LUMI_MASCOT_PNG_BASE64,
    filename: "lumi-mascot.png",
    type: "image/png",
    disposition: "inline",
    content_id: LUMI_MASCOT_CONTENT_ID,
  };
}
